('0871c014-2813-4a61-8926-c5b9ab0d1d52', 'Carrack Copernicus Livery', 'To honor the brave explorers that brought us to space and support those currently seeking new frontiers, the Interstellar Cartography Center (ICC) commissioned this special livery for the Carrack. Named in honor of famed astronomer Nicolaus Copernicus, the livery mixes two shades of blue with black highlights. All proceeds from the sale of the Copernicus livery goes directly to the ICC to support their efforts in "Charting the Way Ahead."', 'Paint_Carrack_Copernicus_LightBlue', 'paint_carrack_copernicus_lightblue', '0e69c8b1-1a09-45c7-92d8-7237c1e44270', ARRAY['Paint_Carrack'], ARRAY['Paint_Carrack'], '{"className":"Paint_Carrack_Copernicus_LightBlue","reference":"0871c014-2813-4a61-8926-c5b9ab0d1d52","itemName":"paint_carrack_copernicus_lightblue","type":"Paints","subType":"UNDEFINED","size":1,"grade":1,"name":"Carrack Copernicus Livery","tags":"Paint_Carrack @Paint_Carrack_Copernicus_LightBlue_Logo","required_tags":"Paint_Carrack","classification":"Ship.Paints","stdItem":{"UUID":"0871c014-2813-4a61-8926-c5b9ab0d1d52","ClassName":"Paint_Carrack_Copernicus_LightBlue","Size":1,"Grade":1,"Width":0.3,"Height":0.2,"Length":0.4,"InventoryOccupancy":{"Dimensions":{"Width":0.3,"Length":0.4,"Height":0.2},"UIDimensions":{"Width":0.75,"Length":0.75,"Height":0.75},"Volume":{"SCU":0.024,"SCUConverted":24000,"Unit":"µSCU"}},"Mass":0,"Type":"Paints.UNDEFINED","Name":"Carrack Copernicus Livery","Description":"To honor the brave explorers that brought us to space and support those currently seeking new frontiers, the Interstellar Cartography Center (ICC) commissioned this special livery for the Carrack. Named in honor of famed astronomer Nicolaus Copernicus, the livery mixes two shades of blue with black highlights. All proceeds from the sale of the Copernicus livery goes directly to the ICC to support their efforts in \"Charting the Way Ahead.\"","DescriptionText":"To honor the brave explorers that brought us to space and support those currently seeking new frontiers, the Interstellar Cartography Center (ICC) commissioned this special livery for the Carrack. Named in honor of famed astronomer Nicolaus Copernicus, the livery mixes two shades of blue with black highlights. All proceeds from the sale of the Copernicus livery goes directly to the ICC to support their efforts in \"Charting the Way Ahead.\"","Manufacturer":{"Name":"Anvil Aerospace","UUID":"0e69c8b1-1a09-45c7-92d8-7237c1e44270"},"Tags":["Paint_Carrack","@Paint_Carrack_Copernicus_LightBlue_Logo"],"RequiredTags":["Paint_Carrack"],"DimensionOverrides":{"Width":0.75,"Length":0.75,"Height":0.75,"Volume":0.216}}}'),
