('e6720b13-ea37-44bd-ac16-418d1b879fbc', 'Prowler Harmony Livery', 'The Harmony livery is meant to showcase Humanity''s peaceful relationship with aliens with a semi-pearlescent blue main coat marked with organic reflective red to suggest the coming together of disparate species and cultures. The Harmony livery has been designed and produced by the UEE''s Diplomatic Corps and freely licensed to all spacecraft manufacturers. Now Esperia Prowler owners can celebrate the UEE''s intentions of working toward a peaceful galaxy.', 'Paint_Prowler_Teal_Red', 'paint_prowler_teal_red', '2e61ca8a-0fc8-40ee-9463-77aab55a5b0a', ARRAY['Paint_Prowler'], ARRAY['Paint_Prowler'], '{"className":"Paint_Prowler_Teal_Red","reference":"e6720b13-ea37-44bd-ac16-418d1b879fbc","itemName":"paint_prowler_teal_red","type":"Paints","subType":"UNDEFINED","size":1,"grade":1,"name":"Prowler Harmony Livery","tags":"Paint_Prowler @Paint_Prowler_Teal_Red","required_tags":"Paint_Prowler","classification":"Ship.Paints","stdItem":{"UUID":"e6720b13-ea37-44bd-ac16-418d1b879fbc","ClassName":"Paint_Prowler_Teal_Red","Size":1,"Grade":1,"Width":0.3,"Height":0.2,"Length":0.4,"InventoryOccupancy":{"Dimensions":{"Width":0.3,"Length":0.4,"Height":0.2},"UIDimensions":{"Width":0.75,"Length":0.75,"Height":0.75},"Volume":{"SCU":0.024,"SCUConverted":24000,"Unit":"µSCU"}},"Mass":0,"Type":"Paints.UNDEFINED","Name":"Prowler Harmony Livery","Description":"The Harmony livery is meant to showcase Humanity''s peaceful relationship with aliens with a semi-pearlescent blue main coat marked with organic reflective red to suggest the coming together of disparate species and cultures. The Harmony livery has been designed and produced by the UEE''s Diplomatic Corps and freely licensed to all spacecraft manufacturers. Now Esperia Prowler owners can celebrate the UEE''s intentions of working toward a peaceful galaxy.","DescriptionText":"The Harmony livery is meant to showcase Humanity''s peaceful relationship with aliens with a semi-pe