('a780540a-0371-4e5f-9924-54cfa13c349e', 'Defender Harmony Livery', 'The Harmony livery is meant to showcase Humanity''s peaceful relationship with aliens with a semi-pearlescent blue main coat marked with organic reflective red to suggest the coming together of disparate species and cultures. The Harmony livery has been designed and produced by the UEE''s Diplomatic Corps and freely licensed to all spacecraft manufacturers. Now Banu Defender owners can celebrate the UEE''s intentions of working toward a peaceful galaxy.', 'Paint_Defender_Teal_Red', 'paint_defender_teal_red', '2f1876f4-1749-4670-98af-ebf465f18255', ARRAY['Paint_Defender'], ARRAY['Paint_Defender'], '{"className":"Paint_Defender_Teal_Red","reference":"a780540a-0371-4e5f-9924-54cfa13c349e","itemName":"paint_defender_teal_red","type":"Paints","subType":"UNDEFINED","size":1,"grade":1,"name":"Defender Harmony Livery","tags":"Paint_Defender @Paint_Defender_Teal_Red","required_tags":"Paint_Defender","classification":"Ship.Paints","stdItem":{"UUID":"a780540a-0371-4e5f-9924-54cfa13c349e","ClassName":"Paint_Defender_Teal_Red","Size":1,"Grade":1,"Width":0.3,"Height":0.2,"Length":0.4,"InventoryOccupancy":{"Dimensions":{"Width":0.3,"Length":0.4,"Height":0.2},"UIDimensions":{"Width":0.75,"Length":0.75,"Height":0.75},"Volume":{"SCU":0.024,"SCUConverted":24000,"Unit":"µSCU"}},"Mass":0,"Type":"Paints.UNDEFINED","Name":"Defender Harmony Livery","Description":"The Harmony livery is meant to showcase Humanity''s peaceful relationship with aliens with a semi-pearlescent blue main coat marked with organic reflective red to suggest the coming together of disparate species and cultures. The Harmony livery has been designed and produced by the UEE''s Diplomatic Corps and freely licensed to all spacecraft manufacturers. Now Banu Defender owners can celebrate the UEE''s intentions of working toward a peaceful galaxy.","DescriptionText":"The Harmony livery is meant to showcase Humanity''s peaceful relationship with aliens with a semi-pearlescent blue main coat marked with organic reflective red to suggest the coming together of disparate species and cultures. The Harmony livery has been designed and produced by the UEE''s Diplomatic Corps and freely licensed to all spacecraft manufacturers. Now Banu Defender owners can celebrate the UEE''s intentions of working toward a peaceful galaxy.","Manufacturer":{"Name":"Banu","UUID":"2f1876f4-1749-4670-98af-ebf465f18255"},"Tags":["Paint_Defender","@Paint_Defender_Teal_Red"],"RequiredTags":["Paint_Defender"],"DimensionOverrides":{"Width":0.75,"Length":0.75,"Height":0.75,"Volume":0.216}}}'),
