('04a3695c-cf61-4bec-a008-9f89302fd2ed', 'Defender Ocellus Livery', 'The Ocellus livery adapts and updates the iconic colors and design used on some Tevarin ships to bring a striking new look to the Defender. The livery gives the fuselage a prominent red section while shimmering green covers the rest of the ship. Thick grey lines swoop through both colors to provide a unique geometric pattern.', 'Paint_Defender_AlienWeek_Green_Red', 'paint_defender_alienweek_green_red', 'd29ebd20-4fc4-498f-8a0e-369b1e649be8', ARRAY['Paint_Defender'], ARRAY['Paint_Defender'], '{"className":"Paint_Defender_AlienWeek_Green_Red","reference":"04a3695c-cf61-4bec-a008-9f89302fd2ed","itemName":"paint_defender_alienweek_green_red","type":"Paints","subType":"UNDEFINED","size":1,"grade":1,"name":"Defender Ocellus Livery","tags":"Paint_Defender @Paint_Defender_AlienWeek_Green_Red","required_tags":"Paint_Defender","classification":"Ship.Paints","stdItem":{"UUID":"04a3695c-cf61-4bec-a008-9f89302fd2ed","ClassName":"Paint_Defender_AlienWeek_Green_Red","Size":1,"Grade":1,"Width":0.3,"Height":0.2,"Length":0.4,"InventoryOccupancy":{"Dimensions":{"Width":0.3,"Length":0.4,"Height":0.2},"UIDimensions":{"Width":0.75,"Length":0.75,"Height":0.75},"Volume":{"SCU":0.024,"SCUConverted":24000,"Unit":"µSCU"}},"Mass":0,"Type":"Paints.UNDEFINED","Name":"Defender Ocellus Livery","Description":"The Ocellus livery adapts and updates the iconic colors and design used on some Tevarin ships to bring a striking new look to the Defender. The livery gives the fuselage a prominent red section while shimmering green covers the rest of the ship. Thick grey lines swoop through both colors to provide a unique geometric pattern.","DescriptionText":"The Ocellus livery adapts and updates the iconic colors and design used on some Tevarin ships to bring a striking new look to the Defender. The livery gives the fuselage a prominent red section while shimmering green covers the rest of the ship. Thick grey lines swoop through both colors to provide a unique geometric pattern.","Manufacturer":{"Name":"Banu","UUID":"d29ebd20-4fc4-498f-8a0e-369b1e649be8"},"Tags":["Paint_Defender","@Paint_Defender_AlienWeek_Green_Red"],"RequiredTags":["Paint_Defender"],"DimensionOverrides":{"Width":0.75,"Length":0.75,"Height":0.75,"Volume":0.216}}}'),
